func NewBluetoothA2dpSinkStub(
	impl IBluetoothA2dpSinkServer,
) IBluetoothA2dpSink {
	wrapper := &bluetoothA2dpSinkStubWrapper{impl: impl}
	stub := &BluetoothA2dpSinkStub{Impl: wrapper}
	wrapper.stubBinder = binder.NewStubBinder(stub)
	return wrapper
}
